Here is an LRU cache with TTL eviction implementing the required interface:

```typescript
// @yakcc:atom:lru-doubly-linked-map
interface Entry<V> {
  value: V;
  expiresAt: number;
  prev: Entry<V> | null;
  next: Entry<V> | null;
  key: unknown;
}

class LRUCacheWithTTL<K, V> {
  private readonly capacity: number;
  private readonly defaultTtlMs: number;
  private readonly map: Map<K, Entry<V>>;
  private readonly head: Entry<V>;
  private readonly tail: Entry<V>;

  constructor(capacity: number, defaultTtlMs: number) {
    this.capacity = capacity;
    this.defaultTtlMs = defaultTtlMs;
    this.map = new Map();
    this.head = { value: undefined as unknown as V, expiresAt: Infinity, prev: null, next: null, key: null };
    this.tail = { value: undefined as unknown as V, expiresAt: Infinity, prev: null, next: null, key: null };
    this.head.next = this.tail;
    this.tail.prev = this.head;
  }

  private isExpired(e: Entry<V>): boolean { return Date.now() >= e.expiresAt; }
  private detach(e: Entry<V>): void {
    if (e.prev) e.prev.next = e.next;
    if (e.next) e.next.prev = e.prev;
    e.prev = null; e.next = null;
  }
  private insertMRU(e: Entry<V>): void {
    e.next = this.head.next; e.prev = this.head;
    if (this.head.next) this.head.next.prev = e;
    this.head.next = e;
  }

  set(key: K, value: V, ttlMs?: number): void {
    const ttl = ttlMs !== undefined ? ttlMs : this.defaultTtlMs;
    const expiresAt = Date.now() + ttl;
    const existing = this.map.get(key);
    if (existing) { existing.value = value; existing.expiresAt = expiresAt; this.detach(existing); this.insertMRU(existing); return; }
    const entry: Entry<V> = { value, expiresAt, prev: null, next: null, key };
    this.map.set(key, entry); this.insertMRU(entry);
    if (this.map.size > this.capacity) { const lru = this.tail.prev!; this.detach(lru); this.map.delete(lru.key as K); }
  }

  get(key: K): V | undefined {
    const e = this.map.get(key); if (!e) return undefined;
    if (this.isExpired(e)) { this.detach(e); this.map.delete(key); return undefined; }
    this.detach(e); this.insertMRU(e); return e.value;
  }

  has(key: K): boolean {
    const e = this.map.get(key); if (!e) return false;
    if (this.isExpired(e)) { this.detach(e); this.map.delete(key); return false; }
    return true;
  }

  delete(key: K): boolean {
    const e = this.map.get(key); if (!e) return false;
    if (this.isExpired(e)) { this.detach(e); this.map.delete(key); return false; }
    this.detach(e); this.map.delete(key); return true;
  }

  size(): number {
    const now = Date.now(); let n = 0;
    for (const [, e] of this.map) if (now < e.expiresAt) n++;
    return n;
  }

  clear(): void { this.map.clear(); this.head.next = this.tail; this.tail.prev = this.head; }
}

export default LRUCacheWithTTL;
